"""
install_calendar_tab.py
Run from C:\\vantro:    python install_calendar_tab.py

Phase D (early): Read-only visual week-grid calendar.

Installs:
  - app/api/admin/calendar/route.ts        (GET aggregator endpoint)
  - components/admin/CalendarTab.tsx       (the week-grid UI)

Patches:
  - components/admin/AdminDashboard.tsx    (registers Calendar tab)

Reads from job_visits + visit_assignments (Phase A migration).
Falls back gracefully if those tables are empty (just shows blank cells).

Idempotent.
"""
import base64, os, sys

API_PATH = os.path.join("app", "api", "admin", "calendar", "route.ts")
TAB_PATH = os.path.join("components", "admin", "CalendarTab.tsx")
DASHBOARD = os.path.join("components", "admin", "AdminDashboard.tsx")

API_B64 = ""
TAB_B64 = ""


def write_file(rel_path, b64_content):
    full = os.path.join(os.getcwd(), rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    contents = base64.b64decode(b64_content).decode("utf-8")
    with open(full, "w", encoding="utf-8", newline="\n") as f:
        f.write(contents)
    print(f"  wrote: {rel_path}  ({len(contents)} bytes)")


def patch_dashboard():
    if not os.path.exists(DASHBOARD):
        print(f"  WARN: {DASHBOARD} not found, skipping")
        return
    with open(DASHBOARD, "r", encoding="utf-8") as f:
        src = f.read()

    if "calendar_tab_marker" in src:
        print(f"  AdminDashboard already patched")
        return

    # 1. Add the import after ScheduleTab import
    old_import = 'import ScheduleTab from "@/components/admin/ScheduleTab"'
    new_import = 'import ScheduleTab from "@/components/admin/ScheduleTab"\nimport CalendarTab from "@/components/admin/CalendarTab" // calendar_tab_marker'
    if old_import not in src:
        print("  ERROR: ScheduleTab import not found in AdminDashboard")
        sys.exit(1)
    src = src.replace(old_import, new_import)

    # 2. Add the render line after the ScheduleTab render
    old_render = '{activeTab === "schedule" && <ScheduleTab />}'
    new_render = '{activeTab === "schedule" && <ScheduleTab />}\n        {activeTab === "calendar" && <CalendarTab />}'
    if old_render not in src:
        print("  ERROR: ScheduleTab render line not found")
        sys.exit(1)
    src = src.replace(old_render, new_render)

    with open(DASHBOARD, "w", encoding="utf-8", newline="\n") as f:
        f.write(src)
    print(f"  PATCHED: {DASHBOARD}")
    print(f"    (import added, render added)")
    print()
    print("  NOTE: You still need to add Calendar to the SIDEBAR tabs array")
    print("  manually. Open AdminDashboard.tsx, search for the existing")
    print("  Schedule entry in your tabs array, copy it, and add a Calendar")
    print('  entry: { id: "calendar", label: "Calendar", ... }')


def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro"):
        print(f"WARNING: cwd is {cwd}")
        print("Run from C:\\vantro. Continue? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    write_file(API_PATH, API_B64)
    write_file(TAB_PATH, TAB_B64)
    print()
    patch_dashboard()
    print()
    print("Done.")
    print()
    print("To test:")
    print("  1. Add Calendar to the sidebar tabs array (see note above)")
    print("  2. git push  -> Vercel deploys")
    print("  3. Open admin -> click Calendar")


if __name__ == "__main__":
    main()
